import React from 'react';
import './Header.css';

function Header() {
  return (
    <header className="header">
      <div className="logo">🌿 Adora</div>
      <nav>
        <ul>
          <li>HOME</li>
          <li>SHOP</li>
          <li>CATEGORY</li>
          <li>ABOUT</li>
          <li>CONTACT</li>
        </ul>
      </nav>
      <div className="cart-icon">🛒</div>
    </header>
  );
}

export default Header;
